# ===================== Message Builder =====================

def build_openai_messages(
    system_prompt,
    context,
    current_chat_history,
    user_prompt,
    user_info=None,
    guidelines=None,
    *,
    context_type=None,
    pipeline_metadata=None,
    user_query=None,
    pipeline_packet_retrieval_context=None,
):
    """Assemble the message list for an OpenAI/Azure call."""
    messages = []

    if system_prompt:
        sys_content = system_prompt
        if guidelines:
            nice = ", ".join(guidelines)
            sys_content += f"\n\nThe following guidelines are currently loaded: {nice}."
        if user_info:
            sys_content += f"\n\nUser Information:\n{user_info}"
        messages.append({"role": "system", "content": sys_content})
    else:
        sys_parts = []
        if guidelines:
            nice = ", ".join(guidelines)
            sys_parts.append(f"The following guidelines are currently loaded: {nice}.")
        if user_info:
            sys_parts.append(f"User Information:\n{user_info}")
        if sys_parts:
            messages.append({"role": "system", "content": "\n\n".join(sys_parts)})

    if context:
        messages.append({"role": "system", "content": f"--- Context ---\n{context}"})

    if context or guidelines or (isinstance(pipeline_packet_retrieval_context, str) and pipeline_packet_retrieval_context.strip()):
        messages.append(
            {
                "role": "system",
                "content": (
                    "--- Citation Formatting Rules ---\n"
                    "When you cite guidelines or retrieved packet documents, copy the provided source label exactly as shown.\n"
                    "Use inline bracket citations in the exact format [filename.pdf - p. 12], [filename.docx - p. 1], or [filename.png - p. 1] when that exact label is provided.\n"
                    "Do not invent citations, rename files, shorten handbook names, or paraphrase source labels.\n"
                    "Every citation must include the full filename and page number; never use shorthand like [p. 505] or [pp. 12-13].\n"
                    "If you include a Sources section, each source must be on its own line or bullet and remain fully bracketed, for example - [Guide.pdf - p. 505].\n"
                    "Never concatenate raw source labels after 'Sources:' without brackets or separators.\n"
                    "Only cite sources you actually relied on in the answer."
                ),
            }
        )

    if context_type == "pipeline":
        uploaded_file_messages = []
        if isinstance(current_chat_history, list):
            for msg in current_chat_history:
                if not isinstance(msg, dict):
                    continue
                if msg.get("display_type") == "file_icon" and isinstance(msg.get("tool_data"), dict):
                    uploaded_file_messages.append(msg)

        manifest = build_pipeline_documents_manifest(
            uploaded_file_messages,
            pipeline_metadata=pipeline_metadata,
            user_query=user_query or user_prompt,
        )
        if manifest:
            messages.append({"role": "system", "content": manifest})
        if isinstance(pipeline_packet_retrieval_context, str) and pipeline_packet_retrieval_context.strip():
            messages.append({"role": "system", "content": pipeline_packet_retrieval_context})
